#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv_m = 1.0 - abs( fract( vUv * 0.5 ) * 2.0 - 1.0 ); // Eo.S' mirror code
ret.x = texture( sampler_fc_main, uv_m ).y*0.65;


vec2 d = uTexSize.zw*6;
vec2 uv_z = (vUvOriginal-0.5)*0.996 + 0.5; // a small dose of zoom-in
vec3 dx = ( GetBlur1(uv_z + vec2(1,0)*d) - GetBlur1(uv_z-vec2(1,0)*d) );
vec3 dy = ( GetBlur1(uv_z + vec2(0,1)*d) - GetBlur1(uv_z-vec2(0,1)*d) );
uv_z -=vec2(dx.z,dy.z)*uTexSize.zw*2; //shortening of the nebulous matter
ret.z = max((tex2d(sampler_fc_main,uv_m).x-0.5)*3*clamp01(1-length(vUvOriginal-0.5)*3.2), // feeded by the inner of the red channel
             tex2d(sampler_fc_main,uv_z).z);
ret.z += (tex2d(sampler_fc_main,uv_z).z - GetBlur1(clamp01(uv_z)).z)*0.02; // sort of geiss' skin dot code


vec2 uv_y = mix(vUv,vUvOriginal,1.0004); // pushing the glassy stuff a little bit
ret.y =max(tex2d(sampler_fc_main,uv_y).y ,tex2d(sampler_fc_main,vUvOriginal).z)-0.008; // feeded by the green channel and fade-out

ret.z *=1+ret.y*0.024;

  fragColor = ret;
}

